<template>
  <scroll-view class="page" scroll-y>
    <view class="tabs">
      <view
        v-for="tab in tabs"
        :key="tab.key"
        class="tab-item"
        :class="{ active: activeTab === tab.key }"
        @click="activeTab = tab.key"
      >
        <text>{{ tab.label }}</text>
      </view>
    </view>

    <view v-for="order in filteredOrders" :key="order.id" class="order-card" @click="openDetail(order)">
      <view class="order-top">
        <view class="order-type-time">
          <text class="order-type">{{ order.type }}</text>
          <text class="order-time"> | {{ order.time }}</text>
        </view>
        <view class="order-status">
          <text v-if="order.status === 'doing'" class="status-blue">进行中</text>
          <text v-else-if="order.status === 'pending'" class="status-orange">待接单</text>
          <text v-else-if="order.status === 'done'" class="status-green">已完成</text>
        </view>
      </view>

      <view class="order-middle">
        <text class="order-title">{{ order.title }}</text>
      </view>
      <view class="order-address">
        <text class="label">送达地址：</text>
        <text class="text">{{ order.address }}</text>
      </view>

      <view class="order-bottom">
        <text class="price">¥{{ order.price }}</text>
        <view class="action-btn" @click.stop="openDetail(order)">
          <text>{{ order.actionText }}</text>
        </view>
      </view>
    </view>
  </scroll-view>
</template>

<script>
export default {
  name: 'OrdersPage',
  data() {
    return {
      tabs: [
        { key: 'all', label: '全部' },
        { key: 'pending', label: '待接单' },
        { key: 'doing', label: '进行中' },
        { key: 'done', label: '已完成' }
      ],
      activeTab: 'all',
      orders: [
        {
          id: '1',
          type: '快递代取',
          time: '2025-12-15 14:30',
          title: '菜鸟驿站取件',
          address: '东区宿舍楼3栋201',
          price: '5',
          status: 'doing',
          actionText: '查看详情'
        },
        {
          id: '2',
          type: '跑腿服务',
          time: '2025-12-15 13:20',
          title: '帮我买一杯咖啡',
          address: '图书馆三楼',
          price: '8',
          status: 'pending',
          actionText: '取消订单'
        },
        {
          id: '3',
          type: '外卖代购',
          time: '2025-12-15 12:00',
          title: '麦当劳套餐',
          address: '西区宿舍楼5栋305',
          price: '15',
          status: 'done',
          actionText: '再来一单'
        },
        {
          id: '4',
          type: '文件打印',
          time: '2025-12-14 16:45',
          title: '打印课程资料20页',
          address: '教学楼A座102',
          price: '10',
          status: 'done',
          actionText: '再来一单'
        }
      ]
    }
  },
  computed: {
    filteredOrders() {
      if (this.activeTab === 'all') return this.orders
      return this.orders.filter(o => o.status === this.activeTab)
    }
  },
  methods: {
    openDetail(order) {
      uni.navigateTo({
        url: `/pages/orders/detail?id=${order.id}`
      })
    }
  }
}
</script>

<style scoped>
.page {
  min-height: 100vh;
  padding: 16rpx 24rpx 24rpx;
  background: #f5f6f7;
  box-sizing: border-box;
}

.tabs {
  margin-top: 8rpx;
  margin-bottom: 16rpx;
  display: flex;
  align-items: center;
}

.tab-item {
  padding: 10rpx 26rpx;
  border-radius: 999rpx;
  margin-right: 16rpx;
  font-size: 26rpx;
  color: #333;
  background: #f2f3f5;
}

.tab-item.active {
  background: #007aff;
  color: #ffffff;
}

.order-card {
  background: #ffffff;
  border-radius: 16rpx;
  padding: 20rpx 20rpx 18rpx;
  margin-bottom: 16rpx;
  box-shadow: 0 4rpx 14rpx rgba(0, 0, 0, 0.03);
}

.order-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 10rpx;
}

.order-type-time {
  display: flex;
  align-items: center;
}

.order-type {
  font-size: 28rpx;
  font-weight: 500;
  color: #333;
}

.order-time {
  font-size: 24rpx;
  color: #999;
  margin-left: 12rpx;
}

.order-status text {
  font-size: 24rpx;
}

.status-blue {
  color: #007aff;
}

.status-orange {
  color: #ff9f1a;
}

.status-green {
  color: #07c160;
}

.order-middle {
  margin-top: 4rpx;
}

.order-title {
  font-size: 28rpx;
  color: #333;
}

.order-address {
  margin-top: 6rpx;
  font-size: 24rpx;
  color: #888;
}

.order-address .label {
  color: #999;
}

.order-bottom {
  margin-top: 14rpx;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.price {
  font-size: 28rpx;
  color: #007aff;
  font-weight: 600;
}

.action-btn {
  padding: 10rpx 26rpx;
  border-radius: 999rpx;
  border: 1rpx solid #007aff;
}

.action-btn text {
  font-size: 24rpx;
  color: #007aff;
}
</style>
